438	pub(crate) fn find_node<T: 'static>(
439	    parent: &Arc<dyn ExecutionPlan>,
440	) -> Option<Arc<dyn ExecutionPlan>> {
441	    //! Used to locate a Node::<T> after the planner converts the logical node
442	    if parent.as_any().downcast_ref::<T>().is_some() {
443	        return Some(parent.to_owned());
444	    }
445	
446	    for child in &parent.children() {
447	        let res = find_node::<T>(child);
448	        if res.is_some() {
449	            return res;
450	        }
451	    }
452	
